sql:
SELECT 
    (SELECT SUM(views) FROM movie_analytics) AS total_views,
    (SELECT AVG(rating) FROM movie_ratings) AS average_rating;

external_knowledge:
- 'Box office haul' refers to the total revenue generated by the movies; 
- 'Combined screen time' refers to the total runtime of the movies; 
- 'Average appeal' refers to the average popularity score of the movies.
